defmodule MyAppWeb.PostLive do
  use Phoenix.LiveView
  
  def render(assigns) do
    ~L"""
    <div>
      <h1>Create a New Post</h1>
      <form phx-submit="save">
        <textarea name="post[content]"><%= @post.content %></textarea>
        <button type="submit">Save Post</button>
      </form>
      <hr />
      <h2>Posts</h2>
      <div><%= raw(@posts |> Enum.map_join("", fn post -> post.content end)) %></div>
    </div>
    """
  end
  
  def handle_event("save", %{"post" => %{"content" => content}}, socket) do
    # You can add validation and processing of the input here
    
    broadcast_from(socket, "new_post", %{content: content})
    
    {:noreply, assign(socket, :posts, [%{content: content} | socket.assigns.posts])}
  end
  
  def handle_info("new_post", payload) do
    # Reload or update the posts list here if needed
    
    {:noreply, assign(socket, :posts, [payload["content"] | socket.assigns.posts])}
  end
end